const text = $json.text || "";
if (!text.trim()) {
  return [{ json: { error: "Missing OCR text in input" } }];
}

// === Clean text ===
const cleanText = text
  .replace(/=== Page \d+ ===/g, "")
  .replace(/--- Page Break ---/g, "")
  .replace(/\s{2,}/g, " ")
  .replace(/\n{2,}/g, "\n")
  .trim();

// === Extract header info ===
const periodMatch = cleanText.match(/Du\s+(\d{2}\/\d{2}\/(\d{4}))\s+au\s+(\d{2}\/\d{2}\/(\d{4}))/i);
const startDateStr = periodMatch ? periodMatch[1] : null;
const endDateStr = periodMatch ? periodMatch[3] : null;
const startYear = periodMatch ? parseInt(periodMatch[2]) : new Date().getFullYear();
const endYear = periodMatch ? parseInt(periodMatch[4]) : startYear;

const companyMatch = cleanText.match(/SAS\s+[A-ZÉÈÊËÀÂÄÎÏÔÖÛÜÇ\s-]+/i);
let company = companyMatch ? companyMatch[0].trim() : null;
if (company && company.includes("Solde au")) company = company.split("Solde au")[0].trim();

const ibanMatch = cleanText.match(/IBAN:\s*([A-Z0-9\s]+)/i);
const bicMatch = cleanText.match(/BIC:\s*([A-Z0-9]+)/i);
let iban = ibanMatch ? ibanMatch[1].replace(/\s+/g, "") : null;
if (iban && iban.includes("BIC")) iban = iban.split("BIC")[0].trim();

const startBalanceMatch = cleanText.match(/Solde au\s+\d{2}\/\d{2}\s*[+-]?\s*([\d.,]+)\s*EUR/i);
const endBalanceMatch = cleanText.match(/Solde au\s+\d{2}\/\d{2}.*?([+-]?\d+[\.,]?\d*)\s*EUR/i);
const totalEntriesMatch = cleanText.match(/Entr[ée]e?s?\s*\+?\s*([\d.,]+)\s*EUR/i);
const totalExitsMatch = cleanText.match(/Sorties\s*-?\s*([\d.,]+)\s*EUR/i);

// === Transaction parsing ===
const lines = cleanText.split("\n");
const transactions = [];
let currentTx = null;
const txRegex = /^(\d{2}\/\d{2})\s+([\wÀ-ÿ0-9&'.\s]+?)\s*([+-])\s*([\d.,]+)\s*EUR/i;

// Helper to determine correct year if period spans two years
function getTransactionYear(month, day) {
  if (startYear === endYear) return startYear;
  const startMonth = parseInt(startDateStr.split("/")[1]);
  const startDay = parseInt(startDateStr.split("/")[0]);
  if (month > startMonth || (month === startMonth && day >= startDay)) {
    return startYear;
  } else {
    return endYear;
  }
}

for (const line of lines) {
  const match = line.trim().match(txRegex);
  if (match) {
    if (currentTx) transactions.push(currentTx);
    const [_, date, label, sign, amountStr] = match;
    const amount = parseFloat(amountStr.replace(",", "."));
    const type = sign === "-" ? "debit" : "credit";
    const [day, month] = date.split("/").map(v => parseInt(v));
    const year = getTransactionYear(month, day);
    const isoDate = `${year}-${month.toString().padStart(2, "0")}-${day.toString().padStart(2, "0")}`;

    currentTx = {
      date: isoDate,
      label: label.trim(),
      amount: type === "debit" ? -amount : amount,
      type,
      description: null,
      category: null
    };
  } else if (currentTx && line && !/EUR|Du\s|IBAN|BIC|Solde|Entr|Sorties/i.test(line)) {
    currentTx.description = (currentTx.description ? currentTx.description + " " : "") + line.trim();
  }
}
if (currentTx) transactions.push(currentTx);

// === Categorize transactions ===
for (const tx of transactions) {
  const desc = (tx.description || "").toLowerCase();
  const label = tx.label.toLowerCase();

  if (desc.includes("facture") || label.includes("client")) tx.category = "Client";
  else if (desc.includes("salaire")) tx.category = "Salaire";
  else if (desc.includes("prélèvement")) tx.category = "Prélèvement";
  else if (desc.includes("carte")) tx.category = "Paiement carte";
  else if (label.includes("qonto") || desc.includes("frais")) tx.category = "Frais bancaires";
  else tx.category = "Fournisseur";
}

// === Compute totals ===
const totalDebit = transactions.filter(t => t.type === "debit").reduce((a, b) => a + Math.abs(b.amount), 0);
const totalCredit = transactions.filter(t => t.type === "credit").reduce((a, b) => a + b.amount, 0);
const balance = totalCredit - totalDebit;

// === Final output ===
return [
  {
    json: {
      summary: {
        company,
        period: startDateStr ? { from: startDateStr, to: endDateStr } : null,
        iban,
        bic: bicMatch ? bicMatch[1] : null,
        start_balance: startBalanceMatch ? parseFloat(startBalanceMatch[1].replace(",", ".")) : null,
        total_credit: totalCredit,
        total_debit: totalDebit,
        balance: endBalanceMatch ? parseFloat(endBalanceMatch[1].replace(",", ".")) : balance,
        count: transactions.length
      },
      transactions,
      raw_text: cleanText
    }
  }
];
